import time
import json
from aiocoap import COAP_INFO, COAP, Resource

# Define the resource paths and their corresponding methods
RESOURCES = {
    '/sensors/temp': {'GET': lambda req: b'25.4'},
    '/actuators/light': {'PUT': lambda req: b'on'}
}

def coap_server():
    # Create the CoAP server
    server = COAP(listen=('0.0.0.0', 5683), multicast=False)
    
    # Add resources to the server
    for path, methods in RESOURCES.items():
        resource = Resource(path, methods)
        server.add_resource(resource)
        
    print('CoAP server started')
    while True:
        try:
            # Listen for incoming CoAP requests and handle them
            request, response = server.recv()
            if request is None:
                break
            method = request.method
            path = request.path
            
            # Check if the request is a GET or PUT request for a resource
            if method in ('GET', 'PUT') and path in RESOURCES:
                # Call the corresponding function to handle the request
                response = RESOURCES[path][method](request)
                
            # Return the response
            server.send(response, response_code=COAP_INFO)
        except Exception as e:
            print('Error:', str(e))
            time.sleep(10)

if __name__ == '__main__':
    coap_server()